```typescript
// 添加输入验证
import validator from 'validator';

search(query: string, limit: number = 20): Iteration[] {
  // 1. 输入清理
  const sanitizedQuery = validator.escape(query.trim());
  const sanitizedLimit = Math.min(Math.max(1, limit), 100); // 限制 1-100

  // 2. 长度限制
  if (sanitizedQuery.length > 500) {
    throw new Error('Search query too long');
  }

  // 3. 使用参数化查询
  return this.db
    .prepare(`
      SELECT * FROM iterations
      WHERE requirement LIKE ?
      ORDER BY started_at DESC
      LIMIT ?
    `)
    .all(`%${sanitizedQuery}%`, sanitizedLimit);
}
