**修复建议**:
```typescript
connection.socket.on('message', (message) => {
  try {
    // 1. 大小限制
    if (message.length > 10240) { // 10KB
      connection.socket.close(1009, 'Message too large');
      return;
    }

    // 2. 格式验证
    const data = JSON.parse(message.toString());

    if (!data.event || typeof data.event !== 'string') {
      connection.socket.send(JSON.stringify({
        event: 'error',
        data: { message: 'Invalid message format' }
      }));
      return;
    }

    // 3. 白名单检查
    const allowedEvents = ['subscribe', 'unsubscribe', 'ping', 'pong'];
    if (!allowedEvents.includes(data.event)) {
      logger.warn({ event: data.event }, 'Unknown WebSocket event');
      return;
    }

    handleWebSocketAction(data, connection.socket);
  } catch (error) {
    logger.error(error, 'Failed to parse WebSocket message');
  }
});
```

