**修复建议**:
```typescript
import { spawn } from 'child_process';

// 安全的方案 1: 使用 spawn 分离参数
private async gitCommit(task: string): Promise<void> {
  try {
    const cwd = this.config.projectPath;

    // 安全的 git add
    await spawn('git', ['add', '.'], { cwd });

    // 安全的 git commit - 参数分离，无 shell 注入风险
    const safeMessage = task.substring(0, 50).replace(/[^\w\s\u4e00-\u9fa5.,!?-]/g, ''); // 过滤特殊字符
    await spawn('git', ['commit', '-m', `auto: ${safeMessage}`], { cwd });

    console.log(`✅ 已提交: auto: ${safeMessage}`);

    if (this.config.autoPush) {
      await spawn('git', ['push'], { cwd });
      console.log('✅ 已推送到远程');
    }
  } catch (error) {
    console.log('⚠️ Git 操作失败:', String(error));
  }
}

// 安全的方案 2: 白名单验证
function sanitizeCommitMessage(msg: string): string {
  // 只允许中文、字母、数字、空格和基本标点
  const allowed = /^[\w\s\u4e00-\u9fa5.,!?+-]+$/
  return msg.split('').filter(c => allowed.test(c)).join('');
}
```

