const SENSITIVE_KEYS = ['AUTH_TOKEN', 'API_KEY', 'PASSWORD', 'SECRET'];
const REDACTED = '[REDACTED]';

function redactSensitiveInfo(obj: any): any {
  if (typeof obj === 'string') {
    return obj;
  }

  const redacted = { ...obj };
