// 1. 输入验证函数
function validateString(input: string, maxLength: number = 10000): string {
  if (typeof input !== 'string') {
    throw new Error('输入必须是字符串');
  }

  if (input.length > maxLength) {
    throw new Error(`输入超过最大长度 ${maxLength}`);
  }

  // 检测潜在的 SQL 注入模式
  const sqlPatterns = [
    /(\b(SELECT|INSERT|UPDATE|DELETE|DROP|CREATE|ALTER)\b)/i,
    /(--|;|\/\*|\*\/)/,
    /(\bOR\b|\bAND\b).*=.*=/i
  ];

  for (const pattern of sqlPatterns) {
    if (pattern.test(input)) {
      throw new Error('检测到潜在的 SQL 注入');
    }
  }

  return input;
}

// 2. 限制查询结果数量
function queryWithLimit(sql: string, params: any[], maxRows: number = 1000) {
  const stmt = db.prepare(sql);
  const results = stmt.all(...params);

  if (results.length > maxRows) {
    throw new Error(`查询结果超过限制 (${maxRows})`);
  }

  return results;
}

