// 1. 日志清理函数
function sanitizeLogInput(input: any): any {
  if (typeof input === 'string') {
    return input
      .replace(/[\x00-\x1F\x7F]/g, '')  // 移除控制字符
      .replace(/\n/g, '\\n')            // 转义换行符
      .replace(/\r/g, '\\r')            // 转义回车符
      .substring(0, 1000);              // 限制长度
