```typescript
export class AutoIterationEngine {
  private maxConcurrentAgents = 3;  // 限制并发数
  private maxIterationsPerDay = 100;  // 每日最大迭代次数
  private dailyIterationCount = 0;
  private lastResetDate = new Date().getDate();

  async start(): Promise<void> {
    // 重置每日计数
    const today = new Date().getDate();
    if (today !== this.lastResetDate) {
      this.dailyIterationCount = 0;
      this.lastResetDate = today;
    }

    while (this.isRunning) {
      // 检查每日限制
      if (this.dailyIterationCount >= this.maxIterationsPerDay) {
        console.log('⚠️ 已达到每日迭代限制');
        this.stop();
        break;
      }

      // 检查系统资源
      const memUsage = process.memoryUsage();
      if (memUsage.heapUsed > 2 * 1024 * 1024 * 1024) { // 2GB
        console.log('⚠️ 内存使用过高，停止迭代');
        this.stop();
        break;
      }

      await this.runIteration();
      this.dailyIterationCount++;

      await this.sleep(this.config.intervalMs);
    }
  }

  // 限制并发 Agent
  private async runIteration(): Promise<void> {
    const semaphore = new Semaphore(this.maxConcurrentAgents);

    const tasks = [
      this.withSemaphore(semaphore, () => this.agents.frontend.executeAndCollect(devPrompt)),
      this.withSemaphore(semaphore, () => this.agents.backend.executeAndCollect(devPrompt)),
      this.withSemaphore(semaphore, () => this.agents.database.executeAndCollect(devPrompt)),
      this.withSemaphore(semaphore, () => this.agents.assets.executeAndCollect(devPrompt))
    ];

    await Promise.all(tasks);
  }

  private withSemaphore(semaphore: Semaphore, fn: () => Promise<any>): Promise<any> {
    return semaphore.acquire().then(release => {
      return fn().finally(release);
    });
  }
}

// 简单信号量实现
class Semaphore {
  private queue: Array<() => void> = [];
  private available: number;

  constructor(count: number) {
    this.available = count;
  }

  acquire(): Promise<() => void> {
    return new Promise(resolve => {
      if (this.available > 0) {
        this.available--;
        resolve(() => this.release());
      } else {
        this.queue.push(() => {
          this.available--;
          resolve(() => this.release());
        });
      }
    });
  }

  private release(): void {
    this.available++;
    if (this.queue.length > 0) {
      const next = this.queue.shift()!;
      next();
    }
  }
}
